import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"44B. Designated Location Bonus","description":"","frontmatter":{"title":"44B. Designated Location Bonus","eba":"Medical Specialists 2022-2026","topics":["allowances"]},"headers":[],"relativePath":"ebas/medical-specialists/allowances/44B-designated-location-bonus.md","filePath":"ebas/medical-specialists/allowances/44B-designated-location-bonus.md"}'),i={name:"ebas/medical-specialists/allowances/44B-designated-location-bonus.md"};function s(r,e,l,p,c,g){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_44b-designated-location-bonus" tabindex="-1">44B. Designated Location Bonus <a class="header-anchor" href="#_44b-designated-location-bonus" aria-label="Permalink to &quot;44B. Designated Location Bonus&quot;">​</a></h1><p><strong>44B.1</strong> Application</p><p><strong>(a)</strong> The purpose of the Designated Location Bonus is to support the recruitment and retention of Doctors employed in Designated Locations in rural and regional Victoria.</p><p><strong>(b)</strong> A Designated Location Bonus is payable to a Doctor employed at a Designated Location, subject to the conditions and eligibility terms set out in this clause after the completion of each Eligible Year of Employment.</p><p><strong>(c)</strong> In this clause 44B.:</p><p><strong>(i)</strong> Designated Location means the Employers listed in subclause 44B.4of this clause</p><p><strong>(ii)</strong> ‘employed at a Designated Location’ means employed at that Designated Location listed at subclause 44B.4 by the Employer who is either named as the Designated Location or who operates the Designated Location.</p><p><strong>(iii)</strong> Eligible Year of Employment means the twelve month period between anniversary dates of commencement at the Designated Location.</p><p><strong>44B.2</strong> Eligibility</p><p><strong>(a)</strong> Subject to the conditions and eligibility terms set out in this clause, a Doctor employed at a Designated Location will receive the Designated Location Bonus after the completion of an Eligible Year of Employment (pro-rata (1/38th) for Fractional Doctors, not payable to Internal Locum Doctors.</p><p><strong>(b)</strong> The Designated Location Bonus:</p><p><strong>(i)</strong> is not payable where the Doctor is already in receipt of an increased or accelerated base rate of pay, and/or is in receipt of a ‘top-up’ payment, specifically set to attract/retain the Doctor to/at their location;</p><p><strong>(ii)</strong> will be subject to offset/absorption, either in full or part, where the Doctor is in receipt of remuneration in excess of the minimum prescribed under this Agreement (including, amongst others, Executive Specialists); and</p><p><strong>(iii)</strong> is not payable where a Doctor’s engagement at a Designated Location is because of a Rotation under the Doctors in Training Agreement (regardless of how the rotation is structured in terms of the employing entity) or other short-term arrangement.</p><p><strong>44B.3</strong> Quantum of Bonus</p><p>The Designated Location Bonus is as follows:</p><p>Date within which the end of their Designated Location Bonus Eligible Year of Employment falls</p><p>1 July 2023 – 30 June 2024 $9,000</p><p>1 July 2024 - 30 June 2025 $10,000</p><p>1 July 2025 – 30 June 2026 $12,000</p><p>Example:</p><p>A Doctor, who is paid per the wage schedule in the Agreement, commences employment at a Designated Location on 1 March 2022, their first Eligible Year of Employment ends on 1 March 2023, as there is no Designated Location Bonus for that date, the Doctor will need to complete a further Eligible Year of Employment to be eligible for the Designated Location Bonus.</p><p>On 1 March 2024, the Doctor finishes their second Eligible Year of Employment. As that date falls within the 1 July 2023 – 30 June 2024 period, they are entitled to a $9,000 Designated Location Bonus.</p><p>Example:</p><p>A Doctor is employed at a Designated Location from 1 March 2023 and is still employed at the Designated Location on 1 March 2024, that period is the Eligible Year of Employment. The Doctor is paid $20,000 above the relevant Agreement rate.</p><p>As the end of their Eligible Year of Employment is within the 1 July 2023 – 30 June 2024 period, they are entitled to a $9,000 Designated Location Bonus, however this is absorbed into their above Agreement rate.</p><p>Example:</p><p>A Doctor is employed at a Designated Location from 1 March 2023 and is still employed at the Designated Location on 1 March 2024, that period is the Eligible Year of Employment. The Doctor is paid $5,000 above the relevant Agreement rate.</p><p>As the end of their Eligible Year of Employment is within the 1 July 2023 – 30 June 2024 period, they are entitled to a $9,000 Designated Location Bonus, as they receive $5,000 above the relevant Agreement rate, this is offset against the $9,000 Designated Location Bonus.</p><p>The Doctor will be entitled to the remaining $4,000 of the Designated Location Bonus.</p><p><strong>44B.4</strong> Designated Locations</p><p>The Designated Locations are as follows:</p><p><strong>(a)</strong> Albury Wodonga Health (Wodonga Hospital only)</p><p><strong>(b)</strong> Bairnsdale Regional Health Service;</p><p><strong>(c)</strong> Central Gippsland Health Service;</p><p><strong>(d)</strong> Echuca Regional Health;</p><p><strong>(e)</strong> Gippsland Southern Health Service;</p><p><strong>(f)</strong> Goulburn Valley Health</p><p><strong>(g)</strong> Horsham Hospital;</p><p><strong>(h)</strong> Mildura Base Public Hospital;</p><p><strong>(i)</strong> Portland District Health;</p><p><strong>(j)</strong> South West Healthcare;</p><p><strong>(k)</strong> Swan Hill District Health;</p><p><strong>(l)</strong> Western District Health Service;</p><p><strong>(m)</strong> Bacchus Marsh Hospital;</p><p><strong>(n)</strong> Bass Coast Health;</p><p><strong>(o)</strong> North East Health Wangaratta; and</p><p><strong>(p)</strong> West Gippsland Healthcare Group</p><p>Plain language terms: location bonus, rural bonus.</p>',49)])])}const m=t(i,[["render",s]]);export{d as __pageData,m as default};
